function printSummary(convData, changed) {
  // 统计（基于原始消息数据，不依赖 latestMessage）
  const now = Date.now();
  const last24h = convData.filter(c => (c.lastContactTime || 0) > now - 86400000).length;

  // 从 chat_history 文件统计客户回复（不是从 latestMessage）
  let totalCustomerMsgs = 0;
  let totalOurMsgs = 0;
  let customersReplied = new Set();
  const CUTOFF = now - 7 * 86400000;

  const chatDir = path.join(DATA_DIR, 'chat_history');
  if (fs.existsSync(chatDir)) {
    const files = fs.readdirSync(chatDir).filter(f => f.endsWith('.json') && f !== '_summary.json');
    for (const file of files) {
      try {
        const data = JSON.parse(fs.readFileSync(path.join(chatDir, file), 'utf-8'));
        for (const msg of (data.messages || [])) {
          const ts = msg.message?.createAt || 0;
          if (ts < CUTOFF) continue;
          const sender = msg.message?.sender?.uid || '';
          const content = msg.message?.content?.text?.content || '';
          if (!content) continue;
          if (sender === '2500000853693@icbu') {
            totalOurMsgs++;
          } else {
            totalCustomerMsgs++;
            customersReplied.add(data.cid || file);
          }
        }
      } catch (e) {}
    }
  }

  log('');
  log('========== 同步摘要 ==========');
  log(`总会话: ${convData.length}`);
  log(`变化会话: ${changed.length}`);
  log(`24h内有 activity: ${last24h}`);
  log('');
  log(`近7天消息 (来自 chat_history 实测):`);
  log(`  客户回复: ${totalCustomerMsgs} 条 / ${customersReplied.size} 人`);
  log(`  我方发送: ${totalOurMsgs} 条`);
  log(`数据已保存到 data/ 目录`);
  log('==============================');
}

// ===================== 启动 =====================

main().catch(err => {
  log(`致命错误: ${err.message}`);
  console.error(err);
  process.exit(1);
});

