const now = Date.now();
const chatDir = path.join(DATA_DIR, 'chat_history');

for (const c of convList) {
  c.preComputed = {};

  // 1. 是否未读
  c.preComputed.isUnread = (c.unreadCount || 0) > 0;

  // 2. 距上次联系天数
  const lct = c.lastContactTimeLong || c.lastContactTime || 0;
  c.preComputed.daysSinceLastContact = lct > 0 ? Math.floor((now - lct) / 86400000) : null;

  // 3. latestMessage 是否是系统消息
  const lmContent = c.latestMessage?.content || '';
  c.preComputed.isLatestMessageSystem = false;
  if (lmContent) {
    for (const pat of SYSTEM_MSG_PATTERNS) {
      if (lmContent.includes(pat)) {
        c.preComputed.isLatestMessageSystem = true;
        break;
      }
    }
  }

  // 4. 是否有 chat_history 文件
  const fileName = sanitizeFilename(c.cid) + '.json';
  const filePath = path.join(chatDir, fileName);
  c.preComputed.hasChatHistoryFile = fs.existsSync(filePath);

  // 5. 是否有真实消息（chat_history 文件中存在非系统消息）
  c.preComputed.hasRealMessages = false;
  if (c.preComputed.hasChatHistoryFile) {
    try {
      const data = JSON.parse(fs.readFileSync(filePath, 'utf-8'));
      for (const msg of (data.messages || [])) {
        const content = msg.message?.content?.text?.content || '';
        if (!content) continue;
        let isSys = false;
        for (const pat of SYSTEM_MSG_PATTERNS) {
          if (content.includes(pat)) { isSys = true; break; }
        }
        if (!isSys) {
          c.preComputed.hasRealMessages = true;
          break;
        }
      }
    } catch (e) {}
  }
}
